def get_politician_info(name):
    politicians = {
        'Enrique Peña Nieto': {
            'affiliation': 'Institutional Revolutionary Party (PRI)',
            'offices': [
                'President of Mexico (2012–2018)',
                'Governor of the State of Mexico (2005–2011)',
                'Local Deputy (2003–2004)',
                'Secretary of Administration (2000–2002)'
            ]
        }
    }
    return politicians.get(name, {'affiliation': 'Unknown', 'offices': []})

# Example usage:
print(get_politician_info('Enrique Peña Nieto'))
